为什么会出现这样的结果？有的是对象，有的是值，之前说过，如果map产出的values的结果只有一个，是不会执行reduce阶段的，这里可以用finalize来保证结果的统一。
db.article.mapReduce(function()&#123;     this.tags.forEach(function(currrnt)&#123;                emit(currrnt, &#123;count:1&#125;)        &#125;);&#125;, function(key, values)&#123;        return values.length;    &#125;, &#123;out:&quot;aa&quot;,finalize: function(key,reduced)&#123;            if(reduced.count) &#123;                return reduced.count;            &#125;            return reduced;        &#125;&#125;);&gt; db.getCollection(&#x27;aa&#x27;).find(&#123;&#125;)&#123; &quot;_id&quot; : &quot;groovy&quot;, &quot;value&quot; : 2 &#125;&#123; &quot;_id&quot; : &quot;java&quot;, &quot;value&quot; : 1 &#125;&#123; &quot;_id&quot; : &quot;kotlin&quot;, &quot;value&quot; : 3 &#125;&#123; &quot;_id&quot; : &quot;mongodb&quot;, &quot;value&quot; : 4 &#125;&#123; &quot;_id&quot; : &quot;perl&quot;, &quot;value&quot; : 4 &#125;&#123; &quot;_id&quot; : &quot;python&quot;, &quot;value&quot; : 1 &#125;&#123; &quot;_id&quot; : &quot;redis&quot;, &quot;value&quot; : 1 &#125;&#123; &quot;_id&quot; : &quot;ruby&quot;, &quot;value&quot; : 3 &#125;&#123; &quot;_id&quot; : &quot;scala&quot;, &quot;value&quot; : 1 &#125;

进阶，mapReduce过滤现在我们只统计发布了java标签的数据，可以用query参数来过滤，也可以用map阶段来用代码过滤。
db.article.mapReduce(function()&#123;     var flag = false;    for(i in this.tags)&#123;        if(this.tags[i] == &#x27;java&#x27;) &#123;            flag = true;            break;        &#125;    &#125;    if(flag) &#123;        this.tags.forEach(function(tag)&#123;            emit(tag, &#123;count:1&#125;);        &#125;);    &#125;&#125;, function(key, values)&#123;        return values.length;    &#125;, &#123;out:&quot;aa&quot;,finalize: function(key,reduced)&#123;            if(reduced.count) &#123;                return reduced.count;            &#125;            return reduced;        &#125;&#125;);&gt; db.getCollection(&#x27;aa&#x27;).find(&#123;&#125;)&#123; &quot;_id&quot; : &quot;java&quot;, &quot;value&quot; : 1 &#125;&#123; &quot;_id&quot; : &quot;mongodb&quot;, &quot;value&quot; : 1 &#125;&#123; &quot;_id&quot; : &quot;python&quot;, &quot;value&quot; : 1 &#125;

聚合框架（aggregation framework）聚合框架是mongo聚合操作的第三种方式，它与group()解决的问题是的一样的，group()和MapReduce都是需要写函数的，所以mongodb提供了聚合框架，简化聚合操作。
注意：只有MapReduce和聚合框架能分片的环境下使用。
聚合框架是不能自定义函数的，它帮我们实现了一些函数。
https://docs.mongodb.com/manual/core/aggregation-pipeline/index.html

聚合框架为我们提供了很多操作，aggregate参数是一个pipeline，每一个按操作按顺序执行。
https://docs.mongodb.com/manual/reference/operator/aggregation/
常用的几个操作：

$project 过滤需要用到的字段

$match 查询，过滤需要用到的数据

$unwind 用于将一个文档拆成多个文档
  {id:tags[‘java’,’python’,’ruby’]}  $unwind  {id:1,tags:’java’},{id:1,tags:’python’},{id:1,tags:’ruby’}

$group 分组，需要指定_id字段为分组的key
  $group本身又提供一些操作：https://docs.mongodb.com/manual/reference/operator/aggregation/group/#accumulator-operator


实例1-长度数据准备：
db.commodity.insert(&#123;category:1, price:200, name: &#x27;name1&#x27;&#125;);db.commodity.insert(&#123;category:1, price:300, name: &#x27;name2&#x27;&#125;);db.commodity.insert(&#123;category:2, price:100, name: &#x27;name3&#x27;&#125;);db.commodity.insert(&#123;category:2, price:500, name: &#x27;name4&#x27;&#125;);db.commodity.insert(&#123;category:3, price:200, name: &#x27;name5&#x27;&#125;);

按照category分组并统计每一组的长度
&gt; db.commodity.aggregate(&#123;$group: &#123;_id:&#x27;$category&#x27;, totalCount: &#123;$sum:1&#125;&#125;&#125;);&#123; &quot;_id&quot; : 3, &quot;totalCount&quot; : 1 &#125;&#123; &quot;_id&quot; : 2, &quot;totalCount&quot; : 2 &#125;&#123; &quot;_id&quot; : 1, &quot;totalCount&quot; : 2 &#125;


实例2-求和&gt; db.commodity.aggregate(&#123;$group: &#123;_id:&#x27;$category&#x27;, totalCount: &#123;$sum:1&#125;, totalPrice: &#123;$sum: &#x27;$price&#x27;&#125;&#125;&#125;);&#123; &quot;_id&quot; : 3, &quot;totalCount&quot; : 1, &quot;totalPrice&quot; : 200 &#125;&#123; &quot;_id&quot; : 2, &quot;totalCount&quot; : 2, &quot;totalPrice&quot; : 600 &#125;&#123; &quot;_id&quot; : 1, &quot;totalCount&quot; : 2, &quot;totalPrice&quot; : 500 &#125;

在没有指定排序规则的时候，aggregate是不保证排序的，需要用$sort指定排序。
&gt; db.commodity.aggregate(&#123;$group: &#123;_id:&#x27;$category&#x27;, totalCount: &#123;$sum:1&#125;, totalPrice: &#123;$sum: &#x27;$price&#x27;&#125;&#125;&#125;, &#123;$sort: &#123;&#x27;totalPrice&#x27;:-1&#125;&#125;);&#123; &quot;_id&quot; : 2, &quot;totalCount&quot; : 2, &quot;totalPrice&quot; : 600 &#125;&#123; &quot;_id&quot; : 1, &quot;totalCount&quot; : 2, &quot;totalPrice&quot; : 500 &#125;&#123; &quot;_id&quot; : 3, &quot;totalCount&quot; : 1, &quot;totalPrice&quot; : 200 &#125;

实例3-求平均值&gt; db.commodity.aggregate(&#123;$group: &#123;_id:&#x27;$category&#x27;, totalCount: &#123;$sum:1&#125;, totalPrice: &#123;$sum: &#x27;$price&#x27;&#125;, avgPrice: &#123;$avg:&#x27;$price&#x27;&#125;&#125;&#125;, &#123;$sort: &#123;&#x27;totalPrice&#x27;:-1&#125;&#125;);&#123; &quot;_id&quot; : 2, &quot;totalCount&quot; : 2, &quot;totalPrice&quot; : 600, &quot;avgPrice&quot; : 300 &#125;&#123; &quot;_id&quot; : 1, &quot;totalCount&quot; : 2, &quot;totalPrice&quot; : 500, &quot;avgPrice&quot; : 250 &#125;&#123; &quot;_id&quot; : 3, &quot;totalCount&quot; : 1, &quot;totalPrice&quot; : 200, &quot;avgPrice&quot; : 200 &#125;


实例4-标签统计之前在演示MapReduce的时候，用MapReduce对article的tags统计tag出现的次数，这里用聚合框架来达到同样的效果，当然想到的就是之前介绍到的$unwind操作。
