public class FastJsonHttpMessageConverter extends AbstractHttpMessageConverter&lt;Object&gt; &#123;        public final static Charset UTF8     = Charset.forName(&quot;UTF-8&quot;);        private Charset             charset  = UTF8;        private SerializerFeature[] features = new SerializerFeature[0];        public FastJsonHttpMessageConverter()&#123;          super(new MediaType(&quot;application&quot;, &quot;json&quot;, UTF8), new MediaType(&quot;application&quot;, &quot;*+json&quot;, UTF8));      &#125;        @Override      protected boolean supports(Class&lt;?&gt; clazz) &#123;          return true;      &#125;        public Charset getCharset() &#123;          return this.charset;      &#125;        public void setCharset(Charset charset) &#123;          this.charset = charset;      &#125;        public SerializerFeature[] getFeatures() &#123;          return features;      &#125;        public void setFeatures(SerializerFeature... features) &#123;          this.features = features;      &#125;        @Override      protected Object readInternal(Class&lt;? extends Object&gt; clazz, HttpInputMessage inputMessage) throws IOException,              HttpMessageNotReadableException &#123;            ByteArrayOutputStream baos = new ByteArrayOutputStream();            InputStream in = inputMessage.getBody();            byte[] buf = new byte[1024];          for (;;) &#123;              int len = in.read(buf);              if (len == -1) &#123;                  break;              &#125;                if (len &gt; 0) &#123;                  baos.write(buf, 0, len);              &#125;          &#125;            byte[] bytes = baos.toByteArray();          return JSON.parseObject(bytes, 0, bytes.length, charset.newDecoder(), clazz);      &#125;        @Override      protected void writeInternal(Object obj, HttpOutputMessage outputMessage) throws IOException,              HttpMessageNotWritableException &#123;            OutputStream out = outputMessage.getBody();          String text = JSONUtil.toJSONString(obj, features);          byte[] bytes = text.getBytes(charset);          out.write(bytes);      &#125;    &#125;  
