public class StreamTest12 &#123;    public static void main(String[] args) &#123;        List&lt;String&gt; list1 = Arrays.asList(&quot;Hi&quot;, &quot;Hello&quot;, &quot;你好&quot;);        List&lt;String&gt; list2 = Arrays.asList(&quot;zhangsan&quot;, &quot;lisi&quot;, &quot;wangwu&quot;, &quot;zhaoliu&quot;);        List&lt;String&gt; result = list1.stream().flatMap(item -&gt; list2.stream().map(item2 -&gt; item + &quot; &quot; + item2)).collect(Collectors.toList());        result.forEach(System.out::println);    &#125;&#125;

分组：group by操作public class StreamTest13 &#123;    public static void main(String[] args) &#123;        Student student1 = new Student(&quot;zhangsan&quot;, 100, 20);        Student student2 = new Student(&quot;lisi&quot;, 90, 20);        Student student3 = new Student(&quot;wangwu&quot;, 90, 30);        Student student4 = new Student(&quot;zhangsan&quot;, 80, 40);        List&lt;Student&gt; students = Arrays.asList(student1, student2, student3, student4);        // select * from student group by name;        /*         * 传统方式：         * 1. 循环列表         * 2. 取出学生名字         * 3. 检查map中是否存在该名字，不存在则直接添加到该map中；存在则将map中的List对象取出来，然后将该Student对象添加到List中         * 4. 返回map对象         */        // 流方式，一行代码        Map&lt;String, List&lt;Student&gt;&gt; map = students.stream().collect(Collectors.groupingBy(Student::getName));        System.out.println(map);        //  select count(*) from student group by name;        Map&lt;String, Long&gt; map1 = students.stream().collect(Collectors.groupingBy(Student::getName, Collectors.counting()));        System.out.println(map1);        // 每个人的平均分        Map&lt;String, Double&gt; map2 = students.stream().collect(Collectors.groupingBy(Student::getName, Collectors.averagingDouble(Student::getScore)));        System.out.println(map2);        // 分区是分组的一种特例，就是用条件来分为两组        Map&lt;Boolean, List&lt;Student&gt;&gt; map3 = students.stream().collect(Collectors.partitioningBy(student -&gt; student.getScore() &gt;= 90));        System.out.println(map3);    &#125;&#125;



