if (accessToken == null) &#123;	throw new InvalidTokenException(&quot;Invalid access token: &quot; + accessTokenValue);&#125;else if (accessToken.isExpired()) &#123;	tokenStore.removeAccessToken(accessToken);	throw new InvalidTokenException(&quot;Access token expired: &quot; + accessTokenValue);&#125;OAuth2Authentication result = tokenStore.readAuthentication(accessToken);if (result == null) &#123;	// in case of race condition	throw new InvalidTokenException(&quot;Invalid access token: &quot; + accessTokenValue);&#125;

想要定制化这个错误消息，需要制定一个AuthExceptionEntryPoint.
@Log4j2@Componentpublic class AuthExceptionEntryPoint implements AuthenticationEntryPoint &#123;    @Autowired    private ObjectMapper objectMapper;    @Override    public void commence(HttpServletRequest request, HttpServletResponse response, AuthenticationException authException) throws IOException, ServletException &#123;        log.info(&quot;Token失效，禁止访问 &#123;&#125;&quot;, request.getRequestURI());        response.setCharacterEncoding(StandardCharsets.UTF_8.displayName());        response.setContentType(MediaType.APPLICATION_JSON_UTF8_VALUE);        RestResp result = RestResp.error(CommonErrorCode.UNAUTHORIZED, &quot;Token错误&quot;);        response.setStatus(HttpStatus.SC_OK);        PrintWriter printWriter = response.getWriter();        printWriter.append(objectMapper.writeValueAsString(result));    &#125;&#125;

然后ResourceServerConfiguration里增加配置
@Override    public void configure(ResourceServerSecurityConfigurer resources) &#123;    resources.expressionHandler(expressionHandler);    resources.authenticationEntryPoint(authExceptionEntryPoint);    resources.accessDeniedHandler(iuMiaoAccessDeniedHandler);    resources.tokenStore(redisTokenStore());&#125;

