从Spring容器中获取到targeter动态代理的组件，Targeter的定义如下：
// FeignAutoConfiguration.java// 这个条件明显是成立的，所以代码拿到的肯定是HystrixTargeter@Configuration@ConditionalOnClass(name = &quot;feign.hystrix.HystrixFeign&quot;)protected static class HystrixFeignTargeterConfiguration &#123;   @Bean   @ConditionalOnMissingBean   public Targeter feignTargeter() &#123;      return new HystrixTargeter();   &#125;&#125;@Configuration@ConditionalOnMissingClass(&quot;feign.hystrix.HystrixFeign&quot;)protected static class DefaultFeignTargeterConfiguration &#123;   @Bean   @ConditionalOnMissingBean   public Targeter feignTargeter() &#123;      return new DefaultTargeter();   &#125;&#125;

在HystrixTargeter中，如果没有开启feign.hystrix.enabled配置，那么就进入默认的Feign.Builder.target方法，不过在生产环境中，一般都会开启。
// HystrixTargeter.java@Overridepublic &lt;T&gt; T target(FeignClientFactoryBean factory, Feign.Builder feign, FeignContext context,               Target.HardCodedTarget&lt;T&gt; target) &#123;   // 默认情况下是Feign.Builder，所以会进入这个逻辑   if (!(feign instanceof feign.hystrix.HystrixFeign.Builder)) &#123;      return feign.target(target);   &#125;   feign.hystrix.HystrixFeign.Builder builder = (feign.hystrix.HystrixFeign.Builder) feign;   SetterFactory setterFactory = getOptional(factory.getName(), context,      SetterFactory.class);   if (setterFactory != null) &#123;      builder.setterFactory(setterFactory);   &#125;   Class&lt;?&gt; fallback = factory.getFallback();   if (fallback != void.class) &#123;      return targetWithFallback(factory.getName(), context, target, builder, fallback);   &#125;   Class&lt;?&gt; fallbackFactory = factory.getFallbackFactory();   if (fallbackFactory != void.class) &#123;      return targetWithFallbackFactory(factory.getName(), context, target, builder, fallbackFactory);   &#125;   return feign.target(target);&#125;



feign.target(target)方法里，将Feign.Builder中所有的的东西集成在一起，构造一个ReflectiveFeign，调用newInstance方法，传入target生成动态代理
// Feign.javapublic &lt;T&gt; T target(Target&lt;T&gt; target) &#123;  return build().newInstance(target);&#125;public Feign build() &#123;  SynchronousMethodHandler.Factory synchronousMethodHandlerFactory =    new SynchronousMethodHandler.Factory(client, retryer, requestInterceptors, logger,                                         logLevel, decode404);  ParseHandlersByName handlersByName =    new ParseHandlersByName(contract, options, encoder, decoder,                            errorDecoder, synchronousMethodHandlerFactory);  return new ReflectiveFeign(handlersByName, invocationHandlerFactory);&#125;

调用newInstance方法，传入target，生成ServiceAClient的动态代理。
// ReflectiveFeign.java@Overridepublic &lt;T&gt; T newInstance(Target&lt;T&gt; target) &#123;  // 关键代码，接口中的每个方法的名称，对应一个处理这个方法的SynchronousMethodHandler  Map&lt;String, MethodHandler&gt; nameToHandler = targetToHandlersByName.apply(target);  // 接口中的每个方法对应的Method对象，对应一个处理这个方法的SynchronousMethodHandler  // 到时候每一个handler，都会去触发真正的调用  Map&lt;Method, MethodHandler&gt; methodToHandler = new LinkedHashMap&lt;Method, MethodHandler&gt;();  List&lt;DefaultMethodHandler&gt; defaultMethodHandlers = new LinkedList&lt;DefaultMethodHandler&gt;();  // 反射遍历ServiceAClient的方法  for (Method method : target.type().getMethods()) &#123;    if (method.getDeclaringClass() == Object.class) &#123;      continue;    &#125; else if(Util.isDefault(method)) &#123;      DefaultMethodHandler handler = new DefaultMethodHandler(method);      defaultMethodHandlers.add(handler);      methodToHandler.put(method, handler);    &#125; else &#123;      methodToHandler.put(method, nameToHandler.get(Feign.configKey(target.type(), method)));    &#125;  &#125;  // 基于工厂创建的InvocationHandler，JDK动态代理的组件, 这里是ReflectiveFeign.FeignInvocationHandler  InvocationHandler handler = factory.create(target, methodToHandler);  // 基于JDK的动态代理创建了一个动态代理对象，这个proxy对象，就实现了ServiceAClient接口  T proxy = (T) Proxy.newProxyInstance(target.type().getClassLoader(), new Class&lt;?&gt;[]&#123;target.type()&#125;, handler);  for(DefaultMethodHandler defaultMethodHandler : defaultMethodHandlers) &#123;    defaultMethodHandler.bindTo(proxy);  &#125;  return proxy;&#125;

