// PredicateBasedRule.java// 用来过滤服务列表的核心逻辑，可利用自己的实现进行个性化的实例过滤public abstract AbstractServerPredicate getPredicate();// 选择服务@Overridepublic Server choose(Object key) &#123;  ILoadBalancer lb = getLoadBalancer();  // 过滤然后轮询选择服务列表  Optional&lt;Server&gt; server = getPredicate().chooseRoundRobinAfterFiltering(lb.getAllServers(), key);  if (server.isPresent()) &#123;    return server.get();  &#125; else &#123;    return null;  &#125;       &#125;

getPredicate().chooseRoundRobinAfterFiltering，先过滤后再用轮询算法选择一个Server。这个具体算法可以在incrementAndGetModulo里找到，算出一个索引值，然后去List里取一个server。
// AbstractServerPredicate.java // 先过滤后，再用轮询算法一次取下一个public Optional&lt;Server&gt; chooseRoundRobinAfterFiltering(List&lt;Server&gt; servers, Object loadBalancerKey) &#123;  // 先过滤服务列表  List&lt;Server&gt; eligible = getEligibleServers(servers, loadBalancerKey);  if (eligible.size() == 0) &#123;    return Optional.absent();  &#125;  return Optional.of(eligible.get(incrementAndGetModulo(eligible.size())));&#125;// 轮训算法计算索引值private int incrementAndGetModulo(int modulo) &#123;  for (;;) &#123;    int current = nextIndex.get();    int next = (current + 1) % modulo;    if (nextIndex.compareAndSet(current, next) &amp;&amp; current &lt; modulo)      return current;  &#125;&#125;


