// LoadBalancerInterceptor.javarequestFactory.createRequest(request, body, execution)// LoadBalancerRequestFactory.javapublic LoadBalancerRequest&lt;ClientHttpResponse&gt; createRequest(final HttpRequest request,                                                               final byte[] body, final ClientHttpRequestExecution execution) &#123;  return new LoadBalancerRequest&lt;ClientHttpResponse&gt;() &#123;    @Override    public ClientHttpResponse apply(final ServiceInstance instance)      throws Exception &#123;      HttpRequest serviceRequest = new ServiceRequestWrapper(request, instance, loadBalancer);      if (transformers != null) &#123;        for (LoadBalancerRequestTransformer transformer : transformers) &#123;          serviceRequest = transformer.transformRequest(serviceRequest, instance);        &#125;      &#125;      return execution.execute(serviceRequest, body);    &#125;  &#125;;&#125;

