// 奥秘所在类public class ServiceRequestWrapper extends HttpRequestWrapper &#123;	private final ServiceInstance instance;	private final LoadBalancerClient loadBalancer;	public ServiceRequestWrapper(HttpRequest request, ServiceInstance instance,								 LoadBalancerClient loadBalancer) &#123;		super(request);		this.instance = instance;		this.loadBalancer = loadBalancer;	&#125;  // 重写了HttpRequest的getURI方法，利用LoadBalancerClient获取到了真正的请求地址。	@Override	public URI getURI() &#123;		URI uri = this.loadBalancer.reconstructURI(				this.instance, getRequest().getURI());		return uri;	&#125;&#125;// RibbonLoadBalancerClient.java// 利用服务实例的host和端口以及path信息，拼接出真正的请求地址// http://serviceA/sayHello -&gt; http://192.168.10.1:8080/sayHello@Overridepublic URI reconstructURI(ServiceInstance instance, URI original) &#123;  Assert.notNull(instance, &quot;instance can not be null&quot;);  String serviceId = instance.getServiceId();  RibbonLoadBalancerContext context = this.clientFactory    .getLoadBalancerContext(serviceId);  URI uri;  Server server;  if (instance instanceof RibbonServer) &#123;    RibbonServer ribbonServer = (RibbonServer) instance;    server = ribbonServer.getServer();    uri = updateToSecureConnectionIfNeeded(original, ribbonServer);  &#125;  else &#123;    server = new Server(instance.getScheme(), instance.getHost(),                        instance.getPort());    IClientConfig clientConfig = clientFactory.getClientConfig(serviceId);    ServerIntrospector serverIntrospector = serverIntrospector(serviceId);    uri = updateToSecureConnectionIfNeeded(original, clientConfig,                                           serverIntrospector, server);  &#125;  return context.reconstructURIWithServer(server, uri);&#125;



