/** * Created by YangFan on 2016/11/28 上午10:01. * &lt;p/&gt; */@Slf4jpublic class JsonWebTokenUtility &#123;    private SignatureAlgorithm signatureAlgorithm;    private Key secretKey;    public JsonWebTokenUtility() &#123;        // 这里不是真正安全的实践        // 为了简单，我们存储一个静态key在这里，        signatureAlgorithm = SignatureAlgorithm.HS512;        String encodedKey =                &quot;L7A/6zARSkK1j7Vd5SDD9pSSqZlqF7mAhiOgRbgv9Smce6tf4cJnvKOjtKPxNNnWQj+2lQEScm3XIUjhW+YVZg==&quot;;        secretKey = deserializeKey(encodedKey);    &#125;    public String createJsonWebToken(AuthTokenDetails authTokenDetails) &#123;        String token =                Jwts.builder().setSubject(authTokenDetails.getId().toString())                        .claim(&quot;username&quot;, authTokenDetails.getUsername())                        .claim(&quot;roleNames&quot;, authTokenDetails.getRoleNames())                        .setExpiration(authTokenDetails.getExpirationDate())                        .signWith(getSignatureAlgorithm(),                                getSecretKey()).compact();        return token;    &#125;    private Key deserializeKey(String encodedKey) &#123;        byte[] decodedKey = Base64.getDecoder().decode(encodedKey);        Key key =                new SecretKeySpec(decodedKey, getSignatureAlgorithm().getJcaName());        return key;    &#125;    private Key getSecretKey() &#123;        return secretKey;    &#125;    public SignatureAlgorithm getSignatureAlgorithm() &#123;        return signatureAlgorithm;    &#125;    public AuthTokenDetails parseAndValidate(String token) &#123;        AuthTokenDetails authTokenDetails = null;        try &#123;            Claims claims =                    Jwts.parser().setSigningKey(getSecretKey()).parseClaimsJws(token).getBody();            String userId = claims.getSubject();            String username = (String) claims.get(&quot;username&quot;);            List&lt;String&gt; roleNames = (List) claims.get(&quot;roleNames&quot;);            Date expirationDate = claims.getExpiration();            authTokenDetails = new AuthTokenDetails();            authTokenDetails.setId(Long.valueOf(userId));            authTokenDetails.setUsername(username);            authTokenDetails.setRoleNames(roleNames);            authTokenDetails.setExpirationDate(expirationDate);        &#125; catch (JwtException ex) &#123;            log.error(ex.getMessage(), ex);        &#125;        return authTokenDetails;    &#125;    private String serializeKey(Key key) &#123;        String encodedKey =                Base64.getEncoder().encodeToString(key.getEncoded());        return encodedKey;    &#125;&#125;

现在我们需要一个定制授权过滤器，将能读取请求头部信息，在Spring中已经有一个这样的授权Filter称为：RequestHeaderAuthenticationFilter，我们只要扩展继承即可：
@Componentpublic class JsonWebTokenAuthenticationFilter extends RequestHeaderAuthenticationFilter &#123;    public JsonWebTokenAuthenticationFilter() &#123;        // Don&#x27;t throw exceptions if the header is missing        this.setExceptionIfHeaderMissing(false);        // This is the request header it will look for        this.setPrincipalRequestHeader(&quot;Authorization&quot;);    &#125;    @Override    @Autowired    public void setAuthenticationManager(            AuthenticationManager authenticationManager) &#123;        super.setAuthenticationManager(authenticationManager);    &#125;&#125;

在这里，头部信息将被转换为Spring Authentication对象，名称为PreAuthenticatedAuthenticationToken我们需要一个授权提供者读取这个记号，然后验证它，然后转换为我们自己的定制授权对象，就是把header里的token转化成我们自己的授权对象。然后把解析之后的对象返回给Spring Security，这里就相当于完成了token-&gt;session的转换。
@Componentpublic class JsonWebTokenAuthenticationProvider implements AuthenticationProvider &#123;    private JsonWebTokenUtility tokenService = new JsonWebTokenUtility();    @Override    public Authentication authenticate(Authentication authentication)            throws AuthenticationException &#123;        Authentication authenticatedUser = null;        // Only process the PreAuthenticatedAuthenticationToken        if (authentication.getClass().                isAssignableFrom(PreAuthenticatedAuthenticationToken.class)                &amp;&amp; authentication.getPrincipal() != null) &#123;            String tokenHeader = (String) authentication.getPrincipal();            UserDetails userDetails = parseToken(tokenHeader);            if (userDetails != null) &#123;                authenticatedUser =                        new JsonWebTokenAuthentication(userDetails, tokenHeader);            &#125;        &#125; else &#123;            // It is already a JsonWebTokenAuthentication            authenticatedUser = authentication;        &#125;        return authenticatedUser;    &#125;    private UserDetails parseToken(String tokenHeader) &#123;        UserDetails principal = null;        AuthTokenDetails authTokenDetails =                tokenService.parseAndValidate(tokenHeader);        if (authTokenDetails != null) &#123;            List&lt;GrantedAuthority&gt; authorities =                    authTokenDetails.getRoleNames().stream()                            .map(SimpleGrantedAuthority::new).collect(Collectors.toList());            // userId介入Spring Security            principal = new User(authTokenDetails.getId().toString(), &quot;&quot;,                    authorities);        &#125;        return principal;    &#125;    @Override    public boolean supports(Class&lt;?&gt; authentication) &#123;        return                authentication.isAssignableFrom(                        PreAuthenticatedAuthenticationToken.class)||                        authentication.isAssignableFrom(                                JsonWebTokenAuthentication.class);    &#125;&#125;

