/** * Created by YangFan on 2016/11/28 上午11:33. * &lt;p/&gt; * 最核心的地方，就是提供某个资源对应的权限定义，即getAttributes方法返回的结果。 * 此类在初始化时，应该取到所有资源及其对应角色的定义。 */@Componentpublic class DemoInvocationSecurityMetadataSourceService implements        FilterInvocationSecurityMetadataSource &#123;    private static Map&lt;String, Collection&lt;ConfigAttribute&gt;&gt; resourceMap = null;    public DemoInvocationSecurityMetadataSourceService() &#123;    &#125;    private void loadResourceDefine() &#123;        /*         * 应当是资源为key， 权限为value。 资源通常为url， 权限就是那些以ROLE_为前缀的角色。 一个资源可以由多个权限来访问。         * sparta         */        Role r = new Role();        r.setId(0L);        r.setName(&quot;admin&quot;);        // 假数据        List&lt;Role&gt; roles = Collections.singletonList(r); // 替换为查询角色列表        resourceMap = new HashMap&lt;&gt;();        for (Role role : roles) &#123;            ConfigAttribute ca = new SecurityConfig(role.getName());            Map&lt;String, Object&gt; params = new HashMap&lt;&gt;();            params.put(&quot;roleId&quot;, role.getId());            // 查询每个角色对于的权限,我这里假设直接查到了url            List&lt;String&gt; resources = Collections.singletonList(&quot;/user/*&quot;);            for (String url : resources) &#123;                /*                 * 判断资源文件和权限的对应关系，如果已经存在相关的资源url，则要通过该url为key提取出权限集合，将权限增加到权限集合中。                 * sparta                 */                if (resourceMap.containsKey(url)) &#123;                    Collection&lt;ConfigAttribute&gt; value = resourceMap.get(url);                    value.add(ca);                    resourceMap.put(url, value);                &#125; else &#123;                    Collection&lt;ConfigAttribute&gt; atts = new ArrayList&lt;&gt;();                    atts.add(ca);                    resourceMap.put(url, atts);                &#125;            &#125;        &#125;    &#125;    @Override    public Collection&lt;ConfigAttribute&gt; getAllConfigAttributes() &#123;        loadResourceDefine();        return null;    &#125;    // 根据URL，找到相关的权限配置。    @Override    public Collection&lt;ConfigAttribute&gt; getAttributes(Object object)            throws IllegalArgumentException &#123;        FilterInvocation filterInvocation = (FilterInvocation) object;        for (String url : resourceMap.keySet()) &#123;            RequestMatcher requestMatcher = new AntPathRequestMatcher(url);            HttpServletRequest httpRequest = filterInvocation.getHttpRequest();            if (requestMatcher.matches(httpRequest)) &#123;                return resourceMap.get(url);            &#125;        &#125;        return null;    &#125;    @Override    public boolean supports(Class&lt;?&gt; arg0) &#123;        return true;    &#125;&#125;

