所有的filter都是通过FilterProcessor.runFilters()方法来执行的，参数作为过滤器的类型来执行对应阶段的
public void preRoute() throws ZuulException &#123;    try &#123;        runFilters(&quot;pre&quot;);    &#125; catch (ZuulException e) &#123;        throw e;    &#125; catch (Throwable e) &#123;        throw new ZuulException(e, 500, &quot;UNCAUGHT_EXCEPTION_IN_PRE_FILTER_&quot; + e.getClass().getName());    &#125;&#125;public Object runFilters(String sType) throws Throwable &#123;    if (RequestContext.getCurrentContext().debugRouting()) &#123;        Debug.addRoutingDebug(&quot;Invoking &#123;&quot; + sType + &quot;&#125; type filters&quot;);    &#125;    boolean bResult = false;    // 根据指定的过滤器类型，比如pre，找到所有的pre类型的过滤器，并且是按照优先级排序的    List&lt;ZuulFilter&gt; list = FilterLoader.getInstance().getFiltersByType(sType);    if (list != null) &#123;        for (int i = 0; i &lt; list.size(); i++) &#123;            ZuulFilter zuulFilter = list.get(i);            Object result = processZuulFilter(zuulFilter);            if (result != null &amp;&amp; result instanceof Boolean) &#123;                bResult |= ((Boolean) result);            &#125;        &#125;    &#125;    return bResult;&#125;

ServletDetectionFilter设置isDispatcherServletRequest&#x3D;true
