PreDecorationFilter这个过滤器逻辑稍显复杂，也是核心的一个逻辑，承担了解析路由的工作

解析请求url，拿到了请求的地址
根据请求的url，分析出来serviceId，然后读取到serviceId对应的route配置，这个routeLocator是SimpleRouteLocator，在这里可以做一定的定制化，将route给做到mysql里去。
将Route规则设置到RequestContext中，加了一些请求头

@Overridepublic Object run() &#123;   RequestContext ctx = RequestContext.getCurrentContext();   // 拿到了请求的url path   final String requestURI = this.urlPathHelper.getPathWithinApplication(ctx.getRequest());   // 根据请求的url，分析出来serviceId，然后读取到serviceId对应的route配置   Route route = this.routeLocator.getMatchingRoute(requestURI);   if (route != null) &#123;      String location = route.getLocation();      if (location != null) &#123;         // route相关规则放进ctx         ctx.put(REQUEST_URI_KEY, route.getPath());         ctx.put(PROXY_KEY, route.getId());         if (!route.isCustomSensitiveHeaders()) &#123;            this.proxyRequestHelper                  .addIgnoredHeaders(this.properties.getSensitiveHeaders().toArray(new String[0]));         &#125;         else &#123;            this.proxyRequestHelper.addIgnoredHeaders(route.getSensitiveHeaders().toArray(new String[0]));         &#125;         if (route.getRetryable() != null) &#123;            ctx.put(RETRYABLE_KEY, route.getRetryable());         &#125;         if (location.startsWith(HTTP_SCHEME+&quot;:&quot;) || location.startsWith(HTTPS_SCHEME+&quot;:&quot;)) &#123;            ctx.setRouteHost(getUrl(location));            // 添加了一些header            ctx.addOriginResponseHeader(SERVICE_HEADER, location);         &#125;         else if (location.startsWith(FORWARD_LOCATION_PREFIX)) &#123;            ctx.set(FORWARD_TO_KEY,                  StringUtils.cleanPath(location.substring(FORWARD_LOCATION_PREFIX.length()) + route.getPath()));            ctx.setRouteHost(null);            return null;         &#125;         else &#123;            // set serviceId for use in filters.route.RibbonRequest            ctx.set(SERVICE_ID_KEY, location);            ctx.setRouteHost(null);            ctx.addOriginResponseHeader(SERVICE_ID_HEADER, location);         &#125;         if (this.properties.isAddProxyHeaders()) &#123;            //             addProxyHeaders(ctx, route);            String xforwardedfor = ctx.getRequest().getHeader(X_FORWARDED_FOR_HEADER);            String remoteAddr = ctx.getRequest().getRemoteAddr();            if (xforwardedfor == null) &#123;               xforwardedfor = remoteAddr;            &#125;            else if (!xforwardedfor.contains(remoteAddr)) &#123; // Prevent duplicates               xforwardedfor += &quot;, &quot; + remoteAddr;            &#125;            ctx.addZuulRequestHeader(X_FORWARDED_FOR_HEADER, xforwardedfor);         &#125;         if (this.properties.isAddHostHeader()) &#123;            ctx.addZuulRequestHeader(HttpHeaders.HOST, toHostHeader(ctx.getRequest()));         &#125;      &#125;   &#125;   else &#123;      log.warn(&quot;No route found for uri: &quot; + requestURI);      String fallBackUri = requestURI;      String fallbackPrefix = this.dispatcherServletPath; // default fallback                                             // servlet is                                             // DispatcherServlet      if (RequestUtils.isZuulServletRequest()) &#123;         // remove the Zuul servletPath from the requestUri         log.debug(&quot;zuulServletPath=&quot; + this.properties.getServletPath());         fallBackUri = fallBackUri.replaceFirst(this.properties.getServletPath(), &quot;&quot;);         log.debug(&quot;Replaced Zuul servlet path:&quot; + fallBackUri);      &#125;      else &#123;         // remove the DispatcherServlet servletPath from the requestUri         log.debug(&quot;dispatcherServletPath=&quot; + this.dispatcherServletPath);         fallBackUri = fallBackUri.replaceFirst(this.dispatcherServletPath, &quot;&quot;);         log.debug(&quot;Replaced DispatcherServlet servlet path:&quot; + fallBackUri);      &#125;      if (!fallBackUri.startsWith(&quot;/&quot;)) &#123;         fallBackUri = &quot;/&quot; + fallBackUri;      &#125;      String forwardURI = fallbackPrefix + fallBackUri;      forwardURI = forwardURI.replaceAll(&quot;//&quot;, &quot;/&quot;);      ctx.set(FORWARD_TO_KEY, forwardURI);   &#125;   return null;&#125;

SimpleRouteLocator这个就是用来读取和保存路由规则的辅助了，用Map维护了一个private AtomicReference&lt;Map&lt;String, ZuulRoute&gt;&gt; routes = new AtomicReference&lt;&gt;();，主要需要关注它的locateRoutes方法，可以继承这个类，然后重写locateRoutes方法，改为从数据库读取路由配置。
protected Map&lt;String, ZuulRoute&gt; locateRoutes() &#123;   LinkedHashMap&lt;String, ZuulRoute&gt; routesMap = new LinkedHashMap&lt;String, ZuulRoute&gt;();   for (ZuulRoute route : this.properties.getRoutes().values()) &#123;      routesMap.put(route.getPath(), route);   &#125;   return routesMap;&#125;

