@Overridepublic Object run() &#123;   RequestContext context = RequestContext.getCurrentContext();   this.helper.addIgnoredHeaders();   try &#123;      // 处理Ribbon相关内容      RibbonCommandContext commandContext = buildCommandContext(context);      // 处理Hystrix，并发送请求      ClientHttpResponse response = forward(commandContext);      setResponse(response);      return response;   &#125;   catch (ZuulException ex) &#123;      throw new ZuulRuntimeException(ex);   &#125;   catch (Exception ex) &#123;      throw new ZuulRuntimeException(ex);   &#125;&#125;

