forward(commandContext);protected ClientHttpResponse forward(RibbonCommandContext context) throws Exception &#123;   Map&lt;String, Object&gt; info = this.helper.debug(context.getMethod(),         context.getUri(), context.getHeaders(), context.getParams(),         context.getRequestEntity());   // 这个代码没有什么新鲜的逻辑，看过Ribbon代码的话就知道，这里面就是封装了一个基于Ribbon和Hystrix的Command   RibbonCommand command = this.ribbonCommandFactory.create(context);   try &#123;      ClientHttpResponse response = command.execute();      this.helper.appendDebug(info, response.getRawStatusCode(), response.getHeaders());      return response;   &#125;   catch (HystrixRuntimeException ex) &#123;      return handleException(info, ex);   &#125;&#125;



ribbonCommandFactory.create最终创建的类是HttpClientRibbonCommand，这个类其实就是一个HystrixCommand，他实现了自己的run方法，在run方法里，就包含了执行请求的逻辑
// AbstractRibbonCommand#run()@Overrideprotected ClientHttpResponse run() throws Exception &#123;   final RequestContext context = RequestContext.getCurrentContext();   RQ request = createRequest();   RS response;      boolean retryableClient = this.client instanceof AbstractLoadBalancingClient         &amp;&amp; ((AbstractLoadBalancingClient)this.client).isClientRetryable((ContextAwareRequest)request);      if (retryableClient) &#123;      response = this.client.execute(request, config);   &#125; else &#123;      // 用负载均衡客户端发起请求,这里面都是ribbon相关的代码了      response = this.client.executeWithLoadBalancer(request, config);   &#125;   context.set(&quot;ribbonResponse&quot;, response);   // Explicitly close the HttpResponse if the Hystrix command timed out to   // release the underlying HTTP connection held by the response.   //   if (this.isResponseTimedOut()) &#123;      if (response != null) &#123;         response.close();      &#125;   &#125;   return new RibbonHttpResponse(response);&#125;



SimpleHostRoutingFilter如果请求是直接配host转发静态路由的，会走这个filter用apache http发送请求
@Overridepublic Object run() &#123;   RequestContext context = RequestContext.getCurrentContext();   HttpServletRequest request = context.getRequest();   MultiValueMap&lt;String, String&gt; headers = this.helper         .buildZuulRequestHeaders(request);   MultiValueMap&lt;String, String&gt; params = this.helper         .buildZuulRequestQueryParams(request);   String verb = getVerb(request);   InputStream requestEntity = getRequestBody(request);   if (getContentLength(request) &lt; 0) &#123;      context.setChunkedRequestBody();   &#125;   String uri = this.helper.buildZuulRequestURI(request);   this.helper.addIgnoredHeaders();   try &#123;      // 利用Apache HttpComponent发送请求      CloseableHttpResponse response = forward(this.httpClient, verb, uri, request,            headers, params, requestEntity);      setResponse(response);   &#125;   catch (Exception ex) &#123;      throw new ZuulRuntimeException(ex);   &#125;   return null;&#125;

SendForwardFilter转发到自己本地的接口
@Overridepublic Object run() &#123;   try &#123;      RequestContext ctx = RequestContext.getCurrentContext();      String path = (String) ctx.get(FORWARD_TO_KEY);      RequestDispatcher dispatcher = ctx.getRequest().getRequestDispatcher(path);      if (dispatcher != null) &#123;         ctx.set(SEND_FORWARD_FILTER_RAN, true);         if (!ctx.getResponse().isCommitted()) &#123;            dispatcher.forward(ctx.getRequest(), ctx.getResponse());            ctx.getResponse().flushBuffer();         &#125;      &#125;   &#125;   catch (Exception ex) &#123;      ReflectionUtils.rethrowRuntimeException(ex);   &#125;   return null;&#125;

post过滤器
900：LocationRewriteFilter
1000：SendResponseFilter

LocationRewriteFilter默认不执行，看响应结果是否需要重定向，如果是的话才会执行。
SendResponseFilter这个就是添加了一些请求头，然后将响应写入Response，

优先写入RequestContext.getCurrentContext().getResponseBody()的内容
然后才是context.getResponseDataStream()，也就是应用返回的内容

