error过滤器
0：SendErrorFilter

SendErrorFilter直接转发到/error路径，这个就是BasicErrorController的路径，所以要想定制异常消息，继承这个类
@Overridepublic Object run() &#123;   try &#123;      RequestContext ctx = RequestContext.getCurrentContext();      ZuulException exception = findZuulException(ctx.getThrowable());      HttpServletRequest request = ctx.getRequest();      request.setAttribute(&quot;javax.servlet.error.status_code&quot;, exception.nStatusCode);      log.warn(&quot;Error during filtering&quot;, exception);      request.setAttribute(&quot;javax.servlet.error.exception&quot;, exception);      if (StringUtils.hasText(exception.errorCause)) &#123;         request.setAttribute(&quot;javax.servlet.error.message&quot;, exception.errorCause);      &#125; 	    // 直接转发到/error路径，这个就是BasicErrorController，所以要想定制异常消息，继承这个类      RequestDispatcher dispatcher = request.getRequestDispatcher(            this.errorPath);      if (dispatcher != null) &#123;         ctx.set(SEND_ERROR_FILTER_RAN, true);         if (!ctx.getResponse().isCommitted()) &#123;            ctx.setResponseStatusCode(exception.nStatusCode);            dispatcher.forward(request, ctx.getResponse());         &#125;      &#125;   &#125;   catch (Exception ex) &#123;      ReflectionUtils.rethrowRuntimeException(ex);   &#125;   return null;&#125;

